import dotenv from 'dotenv';
dotenv.config();
import express from 'express';
import cors from 'cors';
import nodemailer from 'nodemailer';

const app = express();
const PORT = process.env.PORT || 5000;

app.use(cors());
app.use(express.json());

const transporter = nodemailer.createTransport({
  service: 'gmail', // You can change this to another provider if needed
  auth: {
    user: process.env.EMAIL_USER,
    pass: process.env.EMAIL_PASS
  }
});

app.post('/api/register', async (req, res) => {
  const { name, email, college, phone, events } = req.body;

  if (!name || !email) {
    return res.status(400).json({ error: 'Name and email are required.' });
  }

  const mailOptions = {
    from: process.env.EMAIL_USER,
    to: process.env.EMAIL_USER, // Send the notification to yourself
    subject: `Instellation 2024 Registration: ${name}`,
    html: `
      <h2>New Starfleet Cadet Registered!</h2>
      <p><strong>Name:</strong> ${name}</p>
      <p><strong>Email:</strong> ${email}</p>
      <p><strong>College:</strong> ${college}</p>
      <p><strong>Phone:</strong> ${phone}</p>
      <p><strong>Events Selected:</strong></p>
      <ul>
        ${events && events.length > 0 ? events.map(event => `<li>${event}</li>`).join('') : '<li>None</li>'}
      </ul>
    `
  };

  try {
    // 1. Send Email Notification
    const info = await transporter.sendMail(mailOptions);
    console.log('Email sent: ' + info.response);

    // 2. Append to Google Sheets (if webhook exists)
    const webhookUrl = process.env.GOOGLE_SHEET_WEBHOOK;
    if (webhookUrl) {
      const sheetData = {
        name,
        email,
        college,
        phone,
        events: events.join(', ')
      };

      try {
        await fetch(webhookUrl, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(sheetData)
        });
        console.log('Data successfully appended to Google Sheets.');
      } catch (sheetError) {
        console.error('Google Sheets forwarding failed:', sheetError);
        // We log the error but don't fail the entire request, ensuring the user still gets a success if the email sent.
      }
    } else {
      console.log('No GOOGLE_SHEET_WEBHOOK variable found in .env. Skipping spreadsheet insertion.');
    }

    res.status(200).json({ message: 'Transmission successful!' });
  } catch (error) {
    console.error('Error handling registration:', error);
    res.status(500).json({ error: 'Comms failure. Could not process your transmission.' });
  }
});

app.listen(PORT, () => console.log(`Backend server listening at http://localhost:${PORT}`));

