    { category: 'Treasure Hunt', title: 'Starhunt', icon: Map },
    { category: 'BGMI', title: 'Cosmic Combat', icon: Gamepad2 },
    { category: 'Photo Event', title: 'Stellar Shots', icon: Camera },
    { category: 'Tech Talk', title: 'Nebula Narratives', icon: Mic },
  ];

